def install_sdk():
    PKG.mkdir(parents=True, exist_ok=True)
    for rel, content in SDK_FILES.items():
        p = PKG / rel
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(content, encoding="utf-8")
        if p.suffix == ".py":
            py_compile.compile(str(p), doraise=True)
    bridge = PY / "210_Self_Healing_SDK.py"
    bridge.write_text(BRIDGE_SDK, encoding="utf-8")
    py_compile.compile(str(bridge), doraise=True)

def install_generator():
    gen_dir = PKG / "generators"
    gen_dir.mkdir(parents=True, exist_ok=True)
    (gen_dir / "__init__.py").write_text("", encoding="utf-8")
    (gen_dir / "module_generator.py").write_text(GENERATOR_CODE, encoding="utf-8")
    (PY / "210_Module_Generator.py").write_text(RUNNER_GENERATOR, encoding="utf-8")
    py_compile.compile(str(gen_dir / "module_generator.py"), doraise=True)
    py_compile.compile(str(PY / "210_Module_Generator.py"), doraise=True)

def build_modules():
    sys.path.insert(0, str(PKG))
    from generators.module_generator import create_module
    results = []
    for module_id, name, bridge in MODULES:
        results.append(create_module(module_id, name, bridge_name=bridge, overwrite=True)["payload"])
    return results

